import React, { useState } from 'react';
import './App.css';

function App() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    setSelectedFile(file);
    setResults(null);
    setError(null);
    
    // Create image preview
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => setImagePreview(e.target.result);
      reader.readAsDataURL(file);
    } else {
      setImagePreview(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedFile) return;

    setLoading(true);
    setError(null);

    const formData = new FormData();
    formData.append('file', selectedFile);

    try {
      const response = await fetch('http://localhost:8000/analyze', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      setResults(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>🩺 MedAI Chest X-ray Diagnostic Assistant</h1>
        <p>Advanced AI-powered analysis for chest X-ray pathology detection with explainable AI insights</p>
        <div className="header-features">
          <span className="feature-badge">🔬 Grad-CAM++ Heatmaps</span>
          <span className="feature-badge">🤖 AI Explainability</span>
          <span className="feature-badge">⚡ Real-time Analysis</span>
          <span className="feature-badge">🏥 Clinical Decision Support</span>
        </div>
      </header>

      <main className="App-main">
        <div className="upload-section">
          <div className="upload-controls">
            <input
              type="file"
              accept="image/*"
              onChange={handleFileSelect}
              id="file-input"
              style={{ display: 'none' }}
            />
            <label htmlFor="file-input" className="upload-button">
              {selectedFile ? selectedFile.name : 'Choose X-ray Image'}
            </label>

            <button
              onClick={handleAnalyze}
              disabled={!selectedFile || loading}
              className="analyze-button"
            >
              {loading ? '🔬 Analyzing...' : '🚀 Analyze Image'}
            </button>
          </div>

          {imagePreview && (
            <div className="image-preview">
              <h3>📸 Uploaded Image</h3>
              <img src={imagePreview} alt="Uploaded X-ray" className="preview-image" />
            </div>
          )}
        </div>

        {error && (
          <div className="error-message">
            ❌ Error: {error}
          </div>
        )}

        {results && (
          <div className="results-section">
            <h2>Analysis Results</h2>

            {/* Image and Heatmap Display */}
            <div className="image-heatmap-section">
              <div className="image-column">
                <h3>📸 Uploaded X-ray</h3>
                {imagePreview && <img src={imagePreview} alt="Uploaded X-ray" className="result-image" />}
              </div>
              
              {results.heatmap_b64 && (
                <div className="heatmap-column">
                  <h3>🔥 AI Attention Map</h3>
                  <img src={results.heatmap_b64} alt="Grad-CAM Heatmap" className="result-image" />
                </div>
              )}
            </div>

            {/* Binary Pipeline Results - Cleaner Display */}
            <div className="binary-results">
              <h3>🔍 Image Validation Pipeline</h3>
              <div className="binary-grid">
                {results.binary_pipeline.map((result, index) => (
                  <div key={index} className={`binary-item ${result.is_valid ? 'valid' : 'invalid'}`}>
                    <div className="binary-model">{result.model}</div>
                    <div className="binary-status">
                      {result.is_valid ? '✅' : '❌'} {result.message}
                    </div>
                    <div className="binary-confidence">
                      Confidence: {(result.confidence * 100).toFixed(1)}%
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {results.valid_for_analysis ? (
              <>
                {/* AI Explanation */}
                {results.ai_explanation && (
                  <div className="ai-explanation">
                    <h3>🤖 AI-Powered Clinical Explanation</h3>
                    <div className="explanation-content">
                      {results.ai_explanation.split('\n').map((paragraph, index) => (
                        <p key={index}>{paragraph}</p>
                      ))}
                    </div>
                  </div>
                )}

                {/* Clinical Summary */}
                <div className="clinical-summary">
                  <h3>📋 Clinical Assessment</h3>
                  <p className={`assessment-${results.assessment_level.toLowerCase()}`}>
                    {results.clinical_summary}
                  </p>
                </div>

                {/* Pathologies */}
                <div className="pathologies">
                  <h3>🔬 Pathology Analysis</h3>
                  <div className="pathology-grid">
                    {results.pathologies.slice(0, 10).map((pathology, index) => (
                      <div key={index} className="pathology-item">
                        <div className="pathology-name">{pathology.pathology}</div>
                        <div className="pathology-prob">{(pathology.probability * 100).toFixed(1)}%</div>
                        <div className={`confidence-${pathology.confidence_level.toLowerCase()}`}>
                          {pathology.confidence_level}
                        </div>
                        <div className="decision">{pathology.clinical_decision}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Processing Time */}
                <div className="processing-time">
                  ⏱️ Processing time: {results.processing_time_ms}ms
                </div>
              </>
            ) : (
              <div className="invalid-message">
                Image validation failed. Please upload a valid chest X-ray.
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
